def _sign(*, secret, method, path, timestamp, nonce, body: bytes) -> str:
    # Каноническая строка: метод, путь, время, одноразовый nonce, хеш тела.
    body_sha = hashlib.sha256(body or b"").hexdigest()
    payload = f"{method.upper()}\n{path}\n{timestamp}\n{nonce}\n{body_sha}".encode()
    key = hashlib.sha256(secret.encode()).hexdigest()
    return hmac.new(key.encode(), payload, hashlib.sha256).hexdigest()
